//Enemy base statistics eName="Spin Guard" eLevel=11 maxLife=390 life=maxLife pointWorth=16 atkPower=5 resType[1]=4 resType[2]=1 resType[4]=4 resType[5]=2 stunResist=2 baseItemChance=60 baseDropIndex=90 moneyWorth=5 dieSound=0 dieEffect=0 runAcc=1 inactiveDist*=1.25
initSeq=0 shotTime=50 shotDelay=130
